// ── Gnostic Time System ──────────────────────────────────────────────────────
//
// 1 picolorenzo (pLo) = π days = π × 86400 seconds
// Units: barbelo (1 pLo), sophia (9 pLo), kenoma (10 pLo),
//        pleroma (55 pLo), aeon (110 pLo ≈ 345.6 days)
//
// All conversions are exact (no leap-second correction -- that's the God Gap).

/** 1 picolorenzo = π days in seconds */
export const PICOLORENZO_SECONDS = Math.PI * 86400;

/** 
 * THM-CIRCADIAN-GNOSIS-ALIGNMENT
 * Biological drift (24.2h vs 24.0h) = 12 minutes.
 * 12m / 1440m = 1/120 = 1 / (AEON * KENOMA).
 */
export const CIRCADIAN_DRIFT_RATIO = 1 / (GNOSTIC.AEON * GNOSTIC.KENOMA);

/** 1 picolorenzo in milliseconds (for direct Date arithmetic) */
export const PICOLORENZO_MS = PICOLORENZO_SECONDS * 1000;

/** π days of one-minute bars (e.g. signed-out market ledger preview window). */
export const MINUTES_PER_PICOLORENZO = PICOLORENZO_SECONDS / 60;

/** 1 nanolorenzo = 1000 picolorenzos ≈ 8.6 years */
export const NANOLORENZO_SECONDS = PICOLORENZO_SECONDS * 1000;

/** 1 aeon = AEON * KENOMA picolorenzos = 120π days ≈ 377 days */
export const AEON_SECONDS = GNOSTIC.AEON * GNOSTIC.KENOMA * PICOLORENZO_SECONDS;

/**
 * THM-AEON-KENOMA-IDENTITY
 * The product of Aeon and Kenoma is the Syzygy of the Pleroma plus the Kenoma.
 * AEON * KENOMA = 2 * PLEROMA + KENOMA
 * 12 * 10 = 2 * 55 + 10 = 120
 */
export const AEON_KENOMA_IDENTITY = GNOSTIC.AEON * GNOSTIC.KENOMA === 2 * GNOSTIC.PLEROMA + GNOSTIC.KENOMA;

