/** Gravitational constant in m³ kg⁻¹ s⁻². */
export const GRAVITATIONAL_CONSTANT_SI = 6.674e-11;

/** Solar mass in kg. */
export const SOLAR_MASS_KG = 1.989e30;

/** Speed of light in m/s. */
export const SPEED_OF_LIGHT_MS = 2.998e8;

/** One light-year in meters. */
export const LIGHT_YEAR_METERS = 9.461e15;

/** Schwarzschild radius of one solar mass, in light-years. r_s = 2GM/c². */
export const SCHWARZSCHILD_RADIUS_SOLAR_LY =
  (2 * GRAVITATIONAL_CONSTANT_SI * SOLAR_MASS_KG) /
  (SPEED_OF_LIGHT_MS * SPEED_OF_LIGHT_MS) /
  LIGHT_YEAR_METERS;

